/**
 * @fileoverview Textarea constants.
 * @module module/Textarea/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    ROOT:        'textarea',
    WRAPPER:     'textarea-wrapper',
    FIELD:       'textarea-field',
    LABEL:       'textarea-label',
    DESCRIPTION: 'textarea-description',
    HINT:        'textarea-hint',
    FOCUSED:     'is-focused',
    DISABLED:    'is-disabled',
    INVALID:     'is-invalid',
    READONLY:    'is-readonly',
});

export const DEFAULTS = Object.freeze({
    placeholder: '',
    value: '',
    label: null,
    description: null,
    hint: null,
    disabled: false,
    readonly: false,
    required: false,
    rows: 3,
    maxlength: null,
    resize: 'vertical',     // none | vertical | horizontal | both
    name: null,
    onInput: null,
    onChange: null,
    onFocus: null,
    onBlur: null,
});

export const PART = defineParts('Textarea', {
    ROOT        : { class: 'textarea-container', aliases: ['root', 'container'] },
    WRAPPER     : { class: 'textarea-wrapper', aliases: ['wrapper'] },
    FIELD       : { class: 'textarea-field', aliases: ['field', 'textarea'], tag: 'textarea' },
    LABEL       : { class: 'textarea-label', aliases: ['label'], tag: 'label' },
    DESCRIPTION : { class: 'textarea-description', aliases: ['description', 'desc'], tag: 'p' },
    HINT        : { class: 'textarea-hint', aliases: ['hint'], tag: 'p' },
});

PART.ROOT.jit     = 'flex flex-col text-[var(--ta-font-size)] [font-family:var(--ta-font-stack)]';
PART.LABEL.jit    = 'font-medium text-[var(--ta-label-size)] fg-[var(--ta-label-text)] mb-[var(--ta-label-gap)]';
PART.DESCRIPTION.jit = 'text-[var(--ta-desc-size)] fg-[var(--ta-desc-text)] mt-[var(--ta-desc-gap)]';
PART.WRAPPER.jit  = `flex rounded-[var(--ta-radius)] [border:1px_solid_var(--ta-border)] bg-[var(--ta-bg)] ${TRANSITION_COLORS} focus-within:[border-color:var(--ta-focus-border)] focus-within:shadow-[0_0_0_1px_var(--ta-focus-border)] {is-invalid}:[border-color:var(--ta-error-border)] {is-disabled}:opacity-50 {is-disabled}:pointer-events-none mt-[var(--ta-label-gap)] first:mt-0`;
PART.FIELD.jit    = 'w-full bg-transparent border-0 outline-none rounded-[var(--ta-radius)] fg-[var(--ta-text)] px-[var(--ta-px)] py-[var(--ta-py)] text-[var(--ta-font-size)] leading-[var(--ta-line-height)] [resize:var(--ta-resize)] [font-family:inherit] placeholder:fg-[var(--ta-placeholder)]';
PART.HINT.jit     = 'text-[var(--ta-hint-size)] fg-[var(--ta-hint-text)] mt-[var(--ta-hint-gap)]';