/**
 * @fileoverview Textarea barrel.
 * @module module/Textarea
 */
import { default as razyui } from '../index.js';
import { TextareaDef as DEF } from './Textarea.def.js';
import Textarea from './Textarea/index.js';

razyui.Textarea = Textarea;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Textarea);
}

export default Textarea;

export const stylesheet = null;
